/**
 * One-time backfill: re-import TAX CERTIFICATE sheet values from the current
 * Excel files as the source of truth for each fund's tax certificates.
 *
 * Run: node scripts/backfill-tax-certificates.js
 *
 * Notes:
 *   - Uses the same fixed column layout as src/lib/excel-import.ts.
 *   - Existing rows for the same (investor, fund, periodEnd) are updated.
 *   - Any pre-existing rows for the same fund with a DIFFERENT periodEnd are
 *     left alone (they may represent earlier assessment years generated by
 *     the old import-dividends-and-taxcerts.js script).
 */
const fs = require("fs");
const path = require("path");

// Tiny .env loader (we don't want a dotenv dependency just for this script).
try {
  const envPath = path.resolve(__dirname, "..", ".env");
  if (fs.existsSync(envPath)) {
    for (const line of fs.readFileSync(envPath, "utf8").split(/\r?\n/)) {
      const m = line.match(/^\s*([A-Z_][A-Z0-9_]*)\s*=\s*(.*)\s*$/i);
      if (!m) continue;
      let val = m[2];
      if ((val.startsWith('"') && val.endsWith('"')) || (val.startsWith("'") && val.endsWith("'"))) {
        val = val.slice(1, -1);
      }
      if (!(m[1] in process.env)) process.env[m[1]] = val;
    }
  }
} catch {}

const { PrismaClient } = require("@prisma/client");
const ExcelJS = require("exceljs");

// Prefer the direct (non-pooled) URL for long-running batch work — the Supabase
// pooler drops idle connections which kills sequential upserts mid-loop.
const datasourceUrl = process.env.DIRECT_URL || process.env.DATABASE_URL;
const prisma = new PrismaClient({ datasources: { db: { url: datasourceUrl } } });

async function withRetry(op, label) {
  let attempt = 0;
  while (true) {
    try {
      return await op();
    } catch (err) {
      attempt++;
      const code = err?.code || "";
      const msg = err?.message || "";
      const retriable =
        code === "P1017" ||
        code === "P1001" ||
        code === "P1008" ||
        /closed the connection|ECONNRESET|ETIMEDOUT|timeout/i.test(msg);
      if (!retriable || attempt >= 5) throw err;
      const backoff = 500 * 2 ** (attempt - 1);
      console.log(`\n[retry ${attempt}] ${label}: ${code || msg}. Reconnecting in ${backoff}ms...`);
      try { await prisma.$disconnect(); } catch {}
      await new Promise((r) => setTimeout(r, backoff));
      await prisma.$connect();
    }
  }
}

const FILES = [
  { fundCode: "EFUF", file: "EFUF/2026.03.25 INVESTORS.xlsx" },
  { fundCode: "EGF", file: "EGF/EGF_2026.03.25 INVESTORS.xlsx" },
  { fundCode: "ESRF", file: "ESRF/ESRF_2026.03.25 INVESTORS - Copy.xlsx" },
];

function parseNum(val) {
  if (val === null || val === undefined) return 0;
  if (typeof val === "number") return val;
  if (typeof val === "object" && val !== null && "result" in val) {
    const r = val.result;
    if (typeof r === "number") return r;
    if (r === null || r === undefined) return 0;
    return parseNum(r);
  }
  let s = String(val).trim().replace(/,/g, "");
  if (s === "" || s === "-") return 0;
  if (s.startsWith("(") && s.endsWith(")")) s = "-" + s.slice(1, -1);
  const n = parseFloat(s);
  return isNaN(n) ? 0 : n;
}

function parseDate(val) {
  if (val instanceof Date) return val;
  if (typeof val === "number") {
    const epoch = new Date(1899, 11, 30);
    epoch.setDate(epoch.getDate() + val);
    return epoch;
  }
  if (typeof val === "object" && val !== null && "result" in val) {
    return parseDate(val.result);
  }
  if (!val) return null;
  const d = new Date(val);
  return isNaN(d.getTime()) ? null : d;
}

function readPeriodMeta(sheet, rowNum) {
  const row = sheet.getRow(rowNum);
  const y = parseNum(row.getCell(23).value);
  const m = parseNum(row.getCell(24).value);
  const d = parseNum(row.getCell(25).value);
  let date = null;
  if (y && m && d) {
    date = new Date(Date.UTC(y, m - 1, d));
  } else {
    const parsed = parseDate(row.getCell(26).value);
    if (parsed) {
      date = new Date(Date.UTC(parsed.getFullYear(), parsed.getMonth(), parsed.getDate()));
    }
  }
  return { date, nav: parseNum(row.getCell(27).value) };
}

async function main() {
  const funds = await prisma.fund.findMany({ select: { id: true, code: true } });
  const fundMap = new Map(funds.map((f) => [f.code, f.id]));

  const investors = await prisma.investor.findMany({ select: { id: true, investorCode: true } });
  const investorMap = new Map(investors.map((i) => [i.investorCode, i.id]));

  let totalUpserted = 0;

  for (const { fundCode, file } of FILES) {
    const fundId = fundMap.get(fundCode);
    if (!fundId) {
      console.log(`[${fundCode}] fund not found, skipping`);
      continue;
    }

    const wb = new ExcelJS.Workbook();
    await wb.xlsx.readFile(path.resolve(__dirname, "..", file));
    const sheet = wb.worksheets.find((s) => /tax\s*certificate/i.test(s.name));
    if (!sheet) {
      console.log(`[${fundCode}] no TAX CERTIFICATE sheet, skipping`);
      continue;
    }

    const start = readPeriodMeta(sheet, 2);
    const end = readPeriodMeta(sheet, 3);
    if (!end.date) {
      console.log(`[${fundCode}] no period end date found, skipping`);
      continue;
    }

    console.log(
      `[${fundCode}] period ${start.date?.toISOString().slice(0, 10)} → ` +
        `${end.date.toISOString().slice(0, 10)} (NAV start ${start.nav}, end ${end.nav})`
    );

    // Clean up any stale rows for the same fiscal year (handles prior runs
    // that stored periodEnd with a timezone offset and old-script rows at
    // 17:59:59Z of the same calendar day). We delete any row for this fund
    // within a 24h window of the intended UTC-midnight periodEnd.
    const windowStart = new Date(end.date.getTime() - 24 * 60 * 60 * 1000);
    const windowEnd = new Date(end.date.getTime() + 24 * 60 * 60 * 1000);
    const deleted = await withRetry(
      () => prisma.taxCertificate.deleteMany({
        where: { fundId, periodEnd: { gt: windowStart, lt: windowEnd } },
      }),
      `deleteMany ${fundCode}`
    );
    if (deleted.count) {
      console.log(`[${fundCode}] cleaned up ${deleted.count} stale row(s) in ±24h window`);
    }

    let upserted = 0;
    let skipped = 0;

    for (let r = 2; r <= sheet.rowCount; r++) {
      const row = sheet.getRow(r);
      const codeRaw = row.getCell(1).value;
      const code = String(codeRaw || "").trim().toUpperCase();
      if (!/^[A-Z]\d{4,6}$/.test(code)) continue;

      const investorId = investorMap.get(code);
      if (!investorId) {
        skipped++;
        continue;
      }

      const n = (col) => parseNum(row.getCell(col).value);

      const data = {
        periodStart: start.date,
        periodEnd: end.date,
        beginningUnits: n(2),
        beginningCostValue: n(3),
        beginningMarketValue: n(4),
        beginningUnrealizedGain: n(5),
        endingUnits: n(6),
        endingCostValue: n(7),
        endingMarketValue: n(8),
        endingUnrealizedGain: n(9),
        totalUnitsAdded: n(10),
        totalAdditionAtCost: n(11),
        totalUnitsRedeemed: n(12),
        totalRedemptionAtCost: n(13),
        netInvestment: n(14),
        totalRealizedGain: n(15),
        totalGrossDividend: n(16),
        totalTax: n(17),
        totalNetDividend: n(18),
        navAtEnd: end.nav,
      };

      await withRetry(
        () => prisma.taxCertificate.upsert({
          where: {
            investorId_fundId_periodEnd: {
              investorId,
              fundId,
              periodEnd: end.date,
            },
          },
          update: data,
          create: { investorId, fundId, ...data },
        }),
        `upsert ${fundCode}/${code}`
      );
      upserted++;

      if (upserted % 100 === 0) {
        process.stdout.write(`\r  [${fundCode}] ${upserted} upserted...`);
      }
    }

    console.log(`\n[${fundCode}] done: ${upserted} upserted, ${skipped} skipped (unknown investor code)`);
    totalUpserted += upserted;
  }

  console.log(`\nTotal tax certificates upserted: ${totalUpserted}`);
}

main()
  .catch((e) => {
    console.error(e);
    process.exit(1);
  })
  .finally(() => prisma.$disconnect());
